#include <bits/stdc++.h>
using namespace std;
int main(){
	int n,g=0;
	cin>>n;
	int a[3002]{0};
	a[0]=1;
	for(int i=1;i<n;i++){
		a[i]=a[i-1]+i+1;
		g=0;
		for(int j=0;j<=i;j++){
			if(a[j]==a[i-1]-i-1){
				g=1;
				break;
			}
		}
		if(g==0&&a[i-1]-i-1>=1){
			a[i]=a[i-1]-i-1;
		}
	}
	sort(a,a+n);
	for(int i=0;i<n;i++){
		cout<<a[i]<<' ';
	}
	return 0;
}
